def canMeet(t, position, speed):
    left, right = float('-inf'), float('inf')
    for p, s in zip(position, speed):
        left = max(left, p - s * t)
        right = min(right, p + s * t)
    return left <= right

def minTimeToMeet(position, speed):
    low, high = 0, 1e9
    eps = 1e-6  # precision

    while high - low > eps:
        mid = (low + high) / 2
        if canMeet(mid, position, speed):
            high = mid
        else:
            low = mid

    return round(high, 6)

